import React from "react";
import { ChainEthereumIcon } from "./chains/EthereumIcon";
import { ChainBNBIcon } from "./chains/BNBIcon";
import { ChainPolygonIcon } from "./chains/PolygonIcon";
import { ChainArbitrumIcon } from "./chains/ArbitrumIcon";
import { ChainAvalancheIcon } from "./chains/AvalancheIcon";
import { ChainMorphIcon } from "./chains/MorphIcon";

interface ChainIconProps extends React.SVGAttributes<SVGElement> {
  chainId: number;
}

export const ChainIcon = React.forwardRef<SVGSVGElement, ChainIconProps>(
  ({ chainId, ...props }, forwardedRef) => {
    switch (chainId) {
      case 1:
        return <ChainEthereumIcon {...props} />;
      case 10:
        return <ChainPolygonIcon {...props} />;
      case 56:
        return <ChainBNBIcon {...props} />;
      case 137:
        return <ChainPolygonIcon {...props} />;
      case 2810:
        return <ChainMorphIcon {...props} />;
      case 8002:
        return <ChainPolygonIcon {...props} />;
      case 17000:
        return <ChainEthereumIcon {...props} />;
      case 42161:
        return <ChainArbitrumIcon {...props} />;
      case 43114:
        return <ChainAvalancheIcon {...props} />;
      default:
        return <ChainEthereumIcon {...props} />;
    }
  },
);
